import styles from './SignalPanel.module.css';

export default function SignalPanel({ signal, indicators }) {
  const successRate = signal
    ? Math.min(95, Math.max(60, 72 + (signal.score || 0) * 2))
    : null;

  const inds = indicators || {};

  const rsiClass  = !inds.rsi ? 'neutral' : inds.rsi < 38 ? 'bullish' : inds.rsi > 62 ? 'bearish' : 'neutral';
  const macdClass = (inds.macd || 0) >= 0 ? 'bullish' : 'bearish';
  const emaClass  = inds.emaCross ? 'bullish' : 'bearish';
  const bbClass   = !inds.bbPos ? 'neutral' : inds.bbPos < 25 ? 'bullish' : inds.bbPos > 75 ? 'bearish' : 'neutral';

  return (
    <div className={styles.panel}>
      <div className={styles.sectionTitle}>⚡ AL / SAT SİNYALİ</div>

      <div className={`${styles.mainSignal} ${signal ? styles[signal.cls] : ''}`}>
        <div className={styles.sigIcon}>{signal?.icon || '⏳'}</div>
        <div className={styles.sigLabel}>{signal?.type || 'ANALİZ'}</div>
        <div className={styles.sigConf}>
          {signal ? `Güven skoru: ${successRate}%` : 'Coin seçin veya arayın'}
        </div>
      </div>

      {successRate && (
        <div className={styles.successBox}>
          <div className={styles.successLabel}>Başarı Oranı</div>
          <div className={styles.successNum}>{successRate}%</div>
          <div className={styles.bar}>
            <div className={styles.fill} style={{ width: `${successRate}%` }} />
          </div>
        </div>
      )}

      <div className={styles.indGrid}>
        <IndCard label="RSI (14)"   value={inds.rsi || '—'}              cls={rsiClass}  sig={rsiClass === 'bullish' ? '↑ Aşırı Satım' : rsiClass === 'bearish' ? '↓ Aşırı Alım' : '→ Nötr'} />
        <IndCard label="MACD"       value={inds.macd !== undefined ? (inds.macd > 0 ? '+' + inds.macd : inds.macd) : '—'} cls={macdClass} sig={macdClass === 'bullish' ? '↑ Pozitif' : '↓ Negatif'} />
        <IndCard label="EMA 50/200" value={inds.emaCross !== undefined ? (inds.emaCross ? '50 > 200' : '50 < 200') : '—'} cls={emaClass}  sig={emaClass === 'bullish' ? '↑ Golden X' : '↓ Death X'} />
        <IndCard label="Bollinger"  value={inds.bbPos !== undefined ? inds.bbPos + '%' : '—'} cls={bbClass}  sig={bbClass === 'bullish' ? '↑ Alt Bant' : bbClass === 'bearish' ? '↓ Üst Bant' : '→ Orta'} />
      </div>

      {signal?.reason && (
        <div className={styles.reason}>{signal.reason}</div>
      )}
    </div>
  );
}

function IndCard({ label, value, cls, sig }) {
  return (
    <div className={styles.indCard}>
      <div className={styles.indLabel}>{label}</div>
      <div className={`${styles.indValue} ${styles[cls]}`}>{value}</div>
      <div className={`${styles.indSig} ${styles[cls]}`}>{sig}</div>
    </div>
  );
}
